import { moduleMetadata } from '@storybook/angular';
import { PfLinkComponent } from './link.component';
const meta = {
    title: 'Composants graphiques/Link',
    component: PfLinkComponent,
    tags: ['autodocs'],
    parameters: {
        docs: {
            description: {
                component: "Lien stylé avec détection automatique des URLs externes.",
            },
        },
    },
    decorators: [moduleMetadata({ imports: [PfLinkComponent] })],
    argTypes: {
        variant: { control: 'inline-radio', options: ['default', 'quiet'] },
    },
    args: { href: '/demarches', variant: 'default' },
    render: (args) => ({
        props: args,
        template: `<pf-link [href]="href" [variant]="variant">Voir mes démarches en cours</pf-link>`,
    }),
};
export default meta;
export const Default = {};
export const Quiet = {
    args: { variant: 'quiet' },
    render: (args) => ({
        props: args,
        template: `<pf-link [href]="href" [variant]="variant">Modifier mon adresse</pf-link>`,
    }),
};
export const External = {
    args: { href: 'https://www.service-public.fr/' },
    render: (args) => ({
        props: args,
        template: `<pf-link [href]="href">Documentation officielle</pf-link>`,
    }),
};
export const Inline = {
    render: () => ({
        template: `
      <p style="max-width: 480px;">
        Vous pouvez consulter <pf-link href="/cgu">les conditions générales</pf-link>,
        ou en savoir plus sur le <pf-link href="https://www.legifrance.gouv.fr/">cadre juridique applicable</pf-link>.
      </p>
    `,
    }),
};
